def maxPathSum(self, root) -> int:
    self.best = float("-inf")

    def gain(n):
        if not n:
            return 0
        l = max(0, gain(n.left))
        r = max(0, gain(n.right))
        self.best = max(self.best, n.val + l + r)
        return n.val + max(l, r)

    gain(root)
    return self.best
